static zigbee_beacon_info_t* zigbee_select_best_network(zigbee_device_ctx_t *ctx)
{
    if (ctx->discovered_count == 0) {
        return NULL;
    }

    zigbee_beacon_info_t *best = NULL;
    int8_t best_rssi = -128;

    for (uint8_t i = 0; i < ctx->discovered_count; i++) {
        zigbee_beacon_info_t *net = &ctx->discovered_networks[i];

        /* Must have permit joining enabled */
        if (!net->permit_joining) {
            printf("[NETWORK] Skipping network on channel %d - permit join closed\n",
                   net->channel);
            continue;
        }

        /* Must be Zigbee PRO stack profile */
        if (net->stack_profile != 2) {
            continue;
        }

        /* Must have capacity for our device type */
        if (ctx->device_type == ZIGBEE_DEVICE_ROUTER && !net->router_capacity) {
            continue;
        }
        if (ctx->device_type == ZIGBEE_DEVICE_END_DEVICE && !net->end_device_capacity) {
            continue;
        }

        /* Select best RSSI */
        if (net->rssi > best_rssi) {
            best_rssi = net->rssi;
            best = net;
        }
    }

    if (best) {
        printf("[NETWORK] Selected best network: PAN 0x%04X, Channel %d, RSSI %d dBm\n",
               best->pan_id, best->channel, best->rssi);
    }

    return best;
}

